import pytest
from source import wrap

@pytest.mark.parametrize("text, cols, expected", [
    ("aaa bbb ccc", 4, ["aaa", "bbb", "ccc"]),  # Test case for trailing words
    ("abc def", 4, ["abc", "def"]),  # Test case for normal output
])
def test_wrap_trailing_words(text, cols, expected):
    lines = wrap(text, cols)
    assert lines == expected, f"Expected {expected} but got {lines}"
